const normalize = (str = '') =>
  str.toLowerCase()
     .normalize('NFD')
     .replace(/\p{M}/gu, '')
     .trim();

const input = items[0].json;
const output = {};

// base_q: tipo de equipamento em formato pesquisável
output.base_q = normalize(input.tipo_equipamento || '').replace(/_/g, ' ');

// capacidade: só número + ton
if (input.capacidade) {
  const match = input.capacidade.match(/\d+/);
  if (match) output.norm_capacidade = `${match[0]} ton`;
}

// voltagem: só número + v
if (input.voltagem) {
  const match = input.voltagem.match(/\d+/);
  if (match) output.norm_voltagem = `${match[0]}v`;
}

// dimensão: "15x30", "15 x 30", "15 x30cm" → "15 x 30"
if (input.dimensao) {
  const dim = input.dimensao.match(/\d+\s*[x×]\s*\d+/i) || input.dimensao.match(/\d+\D+\d+/);
  if (dim) {
    output.norm_dimensao = normalize(dim[0]).replace(/(\d+)[^\d]+(\d+)/, '$1 x $2');
  }
}

// norma: se não veio diretamente, tenta extrair da descrição do ensaio
if (input.norma) {
  output.norma = normalize(input.norma);
} else if (input.ensaio && input.ensaio.match(/nbr\s*\d+/i)) {
  output.norma = normalize(input.ensaio.match(/nbr\s*\d+/i)[0]);
}

// campos adicionais usados em ranking
['malha', 'diametro', 'resolucao', 'marca'].forEach(campo => {
  if (input[campo]) {
    output[campo] = normalize(input[campo]);
  }
});

// remove campos nulos do output final
const cleaned = Object.fromEntries(Object.entries({ ...input, ...output }).filter(([_, v]) => v != null && v !== ''));

return [{ json: cleaned }];

// 1. Captura todos os resultados SQL em um array
const resultadosSql = $input.all().map(item => item.json);

// 2. Pega o contexto da conversa (pedido original)  
//    vindo do node de normalização, aqui chamado "Code1"
const contextoPedido = $node['Code1'].json;

// 3. Retorna o objeto direto (fora de array, para evitar que a IA ignore)
return [
  {
    json: {
      contexto: contextoPedido,
      resultados: resultadosSql
    }
  }
];

